// Fetch RSS feeds and extract trending topics
const feeds = [
  { name: 'CISA', url: 'https://www.cisa.gov/cybersecurity-advisories/all.xml' },
  { name: 'Dark Reading', url: 'https://www.darkreading.com/rss.xml' },
  { name: 'Krebs', url: 'https://krebsonsecurity.com/feed/' },
  { name: 'Bleeping Computer', url: 'https://www.bleepingcomputer.com/feed/' }
];

const results = [];

for (const feed of feeds) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      timeout: 10000
    });

    // Extract titles from RSS (basic XML parsing)
    const titleMatches = response.match(/<title><!\[CDATA\[([^\]]+)\]\]><\/title>|<title>([^<]+)<\/title>/gi) || [];

    const titles = titleMatches
      .map(t => t.replace(/<\/?title>|<!\[CDATA\[|\]\]>/gi, '').trim())
      .filter(t => t.length > 10)
      .slice(0, 10); // Top 10 from each feed

    results.push(...titles.map(title => ({
      feed: feed.name,
      title,
      timestamp: new Date().toISOString()
    })));
  } catch (error) {
    console.log(`Failed to fetch ${feed.name}: ${error.message}`);
  }
}

console.log(`Fetched ${results.length} total RSS items`);

// Extract trending keywords/topics
const keywords = [];
const topicPatterns = [
  /breach/i, /hack/i, /vulnerability/i, /ransomware/i,
  /zero.trust/i, /compliance/i, /HIPAA/i, /audit/i,
  /IoT/i, /privacy/i, /social.media/i, /healthcare/i,
  /identity/i, /IAM/i, /authentication/i
];

for (const item of results) {
  for (const pattern of topicPatterns) {
    if (pattern.test(item.title)) {
      const match = item.title.match(pattern)[0].toLowerCase();
      keywords.push(match);
    }
  }
}

// Count keyword frequency
const keywordCount = {};
keywords.forEach(k => {
  keywordCount[k] = (keywordCount[k] || 0) + 1;
});

// Sort by frequency
const trending = Object.entries(keywordCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([keyword, count]) => ({ keyword, count }));

console.log('Trending topics:', trending);

return {
  rssItems: results,
  trendingTopics: trending,
  topKeywords: trending.map(t => t.keyword)
};

// Available documents (from your Nextcloud structure)
const documents = [
  { folder: '11JUN25_Bridging_Gap', path: '/Personal/LinkedIn/2025/11JUN25_Bridging_Gap', keywords: ['bridging', 'gap', 'communication', 'skills'], topics: ['skills gap', 'communication', 'knowledge transfer'] },
  { folder: '15JUN25_IAM', path: '/Personal/LinkedIn/2025/15JUN25_IAM', keywords: ['iam', 'identity', 'access', 'management'], topics: ['identity management', 'access control', 'authentication'] },
  { folder: '18JUN25_Think_Like_Client', path: '/Personal/LinkedIn/2025/18JUN25_Think_Like_Client', keywords: ['client', 'thinking', 'perspective'], topics: ['client perspective', 'service delivery', 'customer focus'] },
  { folder: '24JUN25_Automating_ZERO_TRUST_Health', path: '/Personal/LinkedIn/2025/24JUN25_Automating_ZERO_TRUST_Health', keywords: ['automation', 'zero', 'trust', 'health'], topics: ['zero trust', 'automation', 'security architecture'] },
  { folder: '28JUN25_HOMELAB', path: '/Personal/LinkedIn/2025/28JUN25_HOMELAB', keywords: ['homelab', 'infrastructure', 'self-hosting'], topics: ['home lab', 'infrastructure', 'hands-on learning'] },
  { folder: '21JAN26_HealthCare_Breach', path: '/Personal/LinkedIn/2026/21JAN26_HealthCare_Breach', keywords: ['healthcare', 'breach', 'hipaa', 'medical'], topics: ['healthcare security', 'data breach', 'HIPAA compliance'] },
  { folder: '23JAN26_Audit_Failure', path: '/Personal/LinkedIn/2026/23JAN26_Audit_Failure', keywords: ['audit', 'failure', 'compliance', 'assessment'], topics: ['compliance audit', 'audit failure', 'risk assessment'] },
  { folder: '27JAN26_Social_Media', path: '/Personal/LinkedIn/2026/27JAN26_Social_Media', keywords: ['social', 'media', 'engineering', 'security'], topics: ['social media', 'social engineering', 'human factor'] },
  { folder: '29JAN26_IOT_Privacy', path: '/Personal/LinkedIn/2026/29JAN26_IOT_Privacy', keywords: ['iot', 'privacy', 'devices', 'security'], topics: ['IoT security', 'privacy', 'device security'] }
];

// Get trending keywords from previous node
const trendingKeywords = $json.topKeywords || [];
console.log('Trending keywords:', trendingKeywords);

// Check processed files to avoid reusing
const processedFile = '/Personal/LinkedIn/processed_files.txt';
let processedDocs = [];

try {
  // Read processed files list from Nextcloud
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://nextcloud.local.example.home' + processedFile,
    auth: {
      username: $credentials.httpBasicAuth.user,
      password: $credentials.httpBasicAuth.password
    },
    skipSslCertificateValidation: true
  });
  processedDocs = response.split('\n').filter(l => l.trim());
  console.log(`Found ${processedDocs.length} previously processed documents`);
} catch (error) {
  console.log('No processed_files.txt found or error reading it, starting fresh');
}

// Filter out already processed documents
const availableDocs = documents.filter(doc => 
  !processedDocs.includes(doc.folder)
);

console.log(`${availableDocs.length} documents available for processing`);

if (availableDocs.length === 0) {
  throw new Error('All documents have been processed! Please add new content or reset processed_files.txt');
}

// Score documents based on keyword match with trending topics
const scoredDocs = availableDocs.map(doc => {
  let score = 0;
  let matchedKeywords = [];

  for (const trending of trendingKeywords) {
    const trendingLower = trending.toLowerCase();

    // Check if any doc keyword matches trending
    for (const docKeyword of doc.keywords) {
      if (docKeyword.includes(trendingLower) || trendingLower.includes(docKeyword)) {
        score += 10;
        matchedKeywords.push(trending);
      }
    }

    // Check topics
    for (const topic of doc.topics) {
      if (topic.toLowerCase().includes(trendingLower) || trendingLower.includes(topic.toLowerCase())) {
        score += 5;
        matchedKeywords.push(trending);
      }
    }
  }

  return {
    ...doc,
    relevanceScore: score,
    matchedKeywords: [...new Set(matchedKeywords)]
  };
});

// Sort by relevance score (highest first)
scored Docs.sort((a, b) => b.relevanceScore - a.relevanceScore);

// Select the best match, or random if no good match
let selectedDoc;
if (scoredDocs[0].relevanceScore > 0) {
  selectedDoc = scoredDocs[0];
  console.log(`Selected TRENDING document: ${selectedDoc.folder} (score: ${selectedDoc.relevanceScore})`);
} else {
  // No trending match, select randomly from available
  selectedDoc = availableDocs[Math.floor(Math.random() * availableDocs.length)];
  selectedDoc.relevanceScore = 0;
  selectedDoc.matchedKeywords = [];
  console.log(`Selected RANDOM document: ${selectedDoc.folder} (no trending match)`);
}

return {
  ...selectedDoc,
  trendingTopics: trendingKeywords,
  availableCount: availableDocs.length,
  selectionReason: selectedDoc.relevanceScore > 0 ? 'trending_match' : 'random_selection'
};

// Parse XML and find first .md or .docx file
const xml = $input.item.json.data;
const responsePattern = /<d:response>([\s\S]*?)<\/d:response>/g;
const files = [];
let match;

while ((match = responsePattern.exec(xml)) !== null) {
  const responseBlock = match[1];
  const hrefMatch = responseBlock.match(/<d:href>(.*?)<\/d:href>/);
  if (!hrefMatch) continue;

  const href = hrefMatch[1];
  const isFolder = responseBlock.includes('<d:collection');

  if (!isFolder && (href.endsWith('.md') || href.endsWith('.docx'))) {
    files.push(href);
  }
}

if (files.length === 0) {
  throw new Error('No .md or .docx files found in folder');
}

// Select first file
const selectedFile = files[0];
console.log(`Selected file: ${selectedFile}`);

return {
  ...$json,
  selectedFile,
  downloadUrl: 'https://nextcloud.local.example.home' + selectedFile
};

// Extract file content (assuming text/markdown for now)
const fileContent = $input.item.binary?.data ? 
  Buffer.from($input.item.binary.data.data, 'base64').toString('utf-8') :
  $input.item.json.data || '';

if (!fileContent || fileContent.length < 50) {
  throw new Error('File content is empty or too short');
}

console.log(`Extracted ${fileContent.length} characters of content`);

return {
  ...$json,
  fileContent: fileContent.substring(0, 15000), // Limit to 15k chars for Claude
  contentLength: fileContent.length
};

