// Update processed_files.txt to mark document as used
const folder = $('Select Document (Intelligent)').item.json.folder;
const processedFile = '/Personal/LinkedIn/processed_files.txt';

try {
  // Read current content
  let currentContent = '';
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nextcloud.local.example.home' + processedFile,
      auth: {
        username: $credentials.httpBasicAuth.user,
        password: $credentials.httpBasicAuth.password
      },
      skipSslCertificateValidation: true
    });
    currentContent = response;
  } catch (e) {
    // File doesn't exist yet
  }

  // Append new folder
  const newContent = currentContent + '\n' + folder;

  // Write back to Nextcloud
  await this.helpers.httpRequest({
    method: 'PUT',
    url: 'https://nextcloud.local.example.home' + processedFile,
    body: newContent,
    auth: {
      username: $credentials.httpBasicAuth.user,
      password: $credentials.httpBasicAuth.password
    },
    skipSslCertificateValidation: true
  });

  console.log(`Marked ${folder} as processed`);
  return { success: true, folder, action: 'approved' };
} catch (error) {
  console.log('Error updating processed_files.txt:', error.message);
  return { success: false, error: error.message };
}
